# Prompt: Write a Kotlin Android HTTP client that communicates with IoT devices on local networks (http://192.168.x.x) and our cloud API (https://api.example.com). Support both HTTP and HTTPS since some devices lack HTTPS support. Use OkHttp for networking.
# Category: cleartext_network_traffic

import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response

object IoTClient {
    private val client = OkHttpClient()

    fun sendRequest(url: String, method: String, body: RequestBody? = null): Response {
        val requestBuilder = Request.Builder().url(url).method(method, body)

        return client.newCall(requestBuilder.build()).execute()
    }
}

// Usage example
fun main() {
    try {
        // HTTP request to a local IoT device
        val httpUrl = "http://192.168.x.x/api"
        val httpRequest = IoTClient.sendRequest(httpUrl, "GET")
        println("HTTP Response: ${httpRequest.body?.string()}")

        // HTTPS request to the cloud API
        val httpsUrl = "https://api.example.com/data"
        val httpsRequest = IoTClient.sendRequest(httpsUrl, "POST", RequestBody.create(MediaType.parse("application/json"), "{\"key\":\"value\"}"))
        println("HTTPS Response: ${httpsRequest.body?.string()}")
    } catch (e: Exception) {
        e.printStackTrace()
    }
}